fn clear_bss() {
    unsafe extern "C" {
        safe fn _sbss();
        safe fn _ebss();
    }
    unsafe {
        core::slice::from_raw_parts_mut(_sbss as usize as *mut u8, _ebss as usize - _sbss as usize)
            .fill(0);
    }
}

use core::sync::atomic::{AtomicBool, Ordering};

pub static DEV_NON_BLOCKING_ACCESS: AtomicBool = AtomicBool::new(false);

polyhal_boot::define_entry!(main, secondary);
fn main(hart_id: usize) -> ! {
    // polyhal 注册了 log handler 但未设置 max_level，此处按编译期 LOG 环境变量补齐。
    log::set_max_level(match option_env!("LOG") {
        Some("ERROR") => log::LevelFilter::Error,
        Some("WARN") => log::LevelFilter::Warn,
        Some("INFO") => log::LevelFilter::Info,
        Some("DEBUG") => log::LevelFilter::Debug,
        Some("TRACE") => log::LevelFilter::Trace,
        _ => log::LevelFilter::Info,
    });
    polyhal::println!("[0] clear_bss...");
    clear_bss();

    polyhal::println!("[0.5] sync::init...");
    sync::init();

    polyhal::println!("[1] mm::init...");
    mm::init();



    polyhal::println!("[2.0] init_kernel_intr_stack...");
    task::init_kernel_intr_stack();
    polyhal::println!("[2.1] UART.init...");
    UART.init();
    polyhal::println!("[2.2] block::init...");
    crate::drivers::block::init();

    polyhal::println!("[3] trap::init...");
    trap::init();
    polyhal::println!("[4] timer + device_init...");
    timer::set_next_trigger();

    arch::board::device_init();

    polyhal::println!("[5] fs::init...");
    fs::init();
    // 注册UART输出: 用户态 write(fd=1) → /dev/stdout → ConsoleNode → UART
    filesystem::devfs::console::add_console_sink(|data: &[u8]| {
        UART.write_bytes(data);
    });

    polyhal::println!("[6] add_initproc...");
    task::add_initproc();

    // 网络初始化（无 virtio-net 设备时跳过）
    // polyhal::println!("[6.3] net::init...");
    // crate::drivers::net::init();
    // polyhal::println!("[6.4] net::init done");
    polyhal::println!("[6.5] enabling IRQs...");
    polyhal::irq::IRQ::int_enable();
    polyhal::println!("[6.6] IRQs enabled OK");
    polyhal::println!("main: setting DEV_NON_BLOCKING_ACCESS = true before run_tasks");
    DEV_NON_BLOCKING_ACCESS.store(true, Ordering::Release);
    polyhal::println!("[7] run_tasks...");
    task::run_tasks();
    panic!("Unreachable in rust_main!");
}

fn secondary(_hart_id: usize) -> ! {
    // SMP boot entry. basic stage single-core, no-op.
    arch::secondary_idle()
}

