pub fn suspend_current_and_run_next() {
    // There must be an application running.
    let task = take_current_task().unwrap();
    // ---- access current TCB exclusively
    let mut task_inner = task.inner_exclusive_access();
    let kc_ptr = &mut task_inner.kcontext as *mut KContext;
    // Change status to Ready
    task_inner.task_status = TaskStatus::Ready;
    drop(task_inner);
    // ---- release current TCB

    // push back to ready queue.
    add_task(task);
    // jump to scheduling cycle
    schedule(kc_ptr);
}

/// This function must be followed by a schedule
pub fn block_current_task() -> *mut KContext {
    let task = take_current_task().unwrap();
    // Remove from ready queue so it won't be scheduled again until woken.
    TASK_MANAGER.exclusive_access().remove_task(&task);
    let mut task_inner = task.inner_exclusive_access();
    task_inner.task_status = TaskStatus::Blocked;
    note_task_blocked();
    &mut task_inner.kcontext as *mut KContext

