pub fn init() {
    polyhal::println!("  mm: init_heap...");
    heap_allocator::init_heap();
    polyhal::println!("  mm: init_frame_allocator...");
    frame_allocator::init_frame_allocator();
    polyhal::println!("  mm: polyhal::common::init...");
    polyhal::common::init(&PageAllocImpl);
    // Capture the boot-stage page table in the OS layer, like ByteOS.
    init_boot_page_table();
    polyhal::println!("  mm: testing standalone frame_alloc_persist...");
    let test_frame = unsafe { frame_allocator::frame_alloc_persist() };
    polyhal::println!("  mm: frame_alloc_persist returned {:?}", test_frame.map(|p| p.raw()));
    polyhal::println!("  mm: KERNEL_SPACE.activate...");
    polyhal::println!("  mm: forcing lazy init...");
    {
        let _guard = KERNEL_SPACE.exclusive_access();
        polyhal::println!("  mm: lazy init done");
    }
    polyhal::println!("  mm: now activating...");
    let ks = KERNEL_SPACE.exclusive_access();
    polyhal::println!("  mm: about to call activate()...");
    ks.activate();
    polyhal::println!("  mm: activate returned");
    drop(ks);
    polyhal::println!("  mm: done");
}

#[inline]
pub fn activate_kernel_space() {
    let ks = KERNEL_SPACE.exclusive_access();
    ks.activate();
}

#[inline]
pub fn activate_boot_page_table() {
    boot_page_table().change();
}

