const TICKS_PER_SEC: usize = 100;
const NSEC_PER_SEC: usize = 1_000_000_000;
/// check_itimer 每 ITIMER_CHECK_INTERVAL 个 tick 运行一次。
/// 原版每个 tick（100 Hz）都遍历所有进程检查 ITIMER_REAL，
/// 在 LTP 进程数多时是显著开销。降至每 10 个 tick（100ms 粒度）足够。
const ITIMER_CHECK_INTERVAL: usize = 10;

#[repr(C)]
#[derive(Debug, Clone, Copy, Default)]
pub struct Timespec {
    pub tv_sec: i64,
    pub tv_nsec: i64,
}

#[repr(C)]
