}

pub fn get_time_spec() -> Timespec {
    let d = current_time();
    Timespec {
        tv_sec: d.as_secs() as i64,
        tv_nsec: d.subsec_nanos() as i64,
    }
}

pub fn get_time_val() -> Timeval {
    let d = current_time();
    Timeval {
        tv_sec: d.as_secs() as i64,
        tv_usec: d.subsec_micros() as i64,
    }
}

pub fn set_next_trigger() {
    let interval = Duration::from_nanos(NSEC_PER_SEC as u64 / TICKS_PER_SEC as u64);
    let next = current_time() + interval;
    // 每 100 次调用输出一次
    // static ST_COUNT: AtomicUsize = AtomicUsize::new(0);
    // let n = ST_COUNT.fetch_add(1, AtomicOrdering::Relaxed) + 1;
    // if n % 100 == 0 || n >= 198 {
    //     polyhal::println!("[set_next_trigger] #{} next={}.{:03}s", n, next.as_secs(), next.subsec_millis());
    // }
    set_next_timer(next);
}

/// Arm the hardware timer for the nearest pending timeout:
/// min(10ms tick, earliest timer in heap).  Called when a task blocks
/// so we are never solely dependent on the periodic tick surviving.
pub fn arm_for_nearest() {
    let tick_interval = Duration::from_nanos(NSEC_PER_SEC as u64 / TICKS_PER_SEC as u64);
    let next_tick = current_time() + tick_interval;

    let candidate = TIMERS.exclusive_session(|timers| {
        timers.peek().map(|t| Duration::from_millis(t.expire_ms as u64))
    });

    let target = match candidate {
        Some(t) if t < next_tick => t,
        _ => next_tick,
    };

    set_next_timer(target);
}

pub struct TimerCondVar {
    pub expire_ms: usize,
    pub task: Arc<TaskControlBlock>,
}

impl PartialEq for TimerCondVar {
    fn eq(&self, other: &Self) -> bool {
        self.expire_ms == other.expire_ms
    }
}
impl Eq for TimerCondVar {}
impl PartialOrd for TimerCondVar {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        let a = -(self.expire_ms as isize);
        let b = -(other.expire_ms as isize);
        Some(a.cmp(&b))
    }
}

impl Ord for TimerCondVar {
    fn cmp(&self, other: &Self) -> Ordering {
        self.partial_cmp(other).unwrap()
    }
}

lazy_static! {
    static ref TIMERS: UPIntrFreeCell<BinaryHeap<TimerCondVar>> =
        unsafe { UPIntrFreeCell::with_name(BinaryHeap::<TimerCondVar>::new(), "TIMERS") };
}

pub fn add_timer(expire_ms: usize, task: Arc<TaskControlBlock>) {
    let mut timers = TIMERS.exclusive_access();
    timers.push(TimerCondVar { expire_ms, task });
}

pub fn check_timer() {
    let current_ms = get_time_ms();
    let mut has_pending = false;
    TIMERS.exclusive_session(|timers| {
        while let Some(timer) = timers.peek() {
            if timer.expire_ms <= current_ms {
                wakeup_task(Arc::clone(&timer.task));
                timers.pop();
            } else {
                has_pending = true;
                break;
            }
        }
    });
    // 有未到期的定时器时，将硬件 timer 武装到最近的到期时间，
    // 确保即使周期性 tick 中断丢失，任务也能在准确时间被唤醒。
    if has_pending {
        arm_for_nearest();
    }
    // itimer 检查降频：每 ITIMER_CHECK_INTERVAL 个 tick 运行一次，
    // 将 O(进程数) 的遍历从 100 Hz 降至 10 Hz。
    static ITIMER_TICK: AtomicUsize = AtomicUsize::new(0);
    let n = ITIMER_TICK.fetch_add(1, AtomicOrdering::Relaxed) + 1;
    if n >= ITIMER_CHECK_INTERVAL {
        ITIMER_TICK.store(0, AtomicOrdering::Relaxed);
        check_itimer(current_ms);
    }
}

fn check_itimer(current_ms: usize) {
    use crate::task::{all_processes, add_signal_to_process, signal::SigInfo};
    const SIGALRM: usize = 14;
    for proc in all_processes() {
        let expired = {
            match proc.try_inner_exclusive_access() {
                Some(mut inner) => {
                    match inner.itimer_real_expire_ms {
                        Some(exp) if exp <= current_ms => {
                            inner.itimer_real_expire_ms = None;
                            true
                        }
                        _ => false,
                    }
                }
                None => false,
            }
        };
        if expired {
            let si = SigInfo::user_signal(SIGALRM as i32);
            add_signal_to_process(&proc, SIGALRM, si);
        }
    }
}

