pub struct TimeStat {
    pub utime: isize,
    pub stime: isize,
    pub cutime: isize,
    pub cstime: isize,
    pub lasttime: isize,
}

impl TimeStat {
    pub fn new() -> Self {
        let now = get_time_ms() as isize;
        Self {
            utime: 0,
            stime: 0,
            cutime: 0,
            cstime: 0,
            lasttime: now,
        }
    }

    pub fn update_utime(&mut self) {
        let now = get_time_ms() as isize;
        let duration = now - self.lasttime;
        self.utime += duration;
        self.lasttime = now;
    }

    pub fn update_stime(&mut self) {
        let now = get_time_ms() as isize;
        let duration = now - self.lasttime;
        self.stime += duration;
        self.lasttime = now;
    }

    pub fn clear(&mut self) {
        let now = get_time_ms() as isize;
        self.utime = 0;
        self.stime = 0;
        self.cutime = 0;
        self.cstime = 0;
        self.lasttime = now;
    }
}

