// ============================================================
// 用户地址空间布局 (Sv39, 256 GB user space)
// ============================================================
//
// 低地址                                                高地址
// [ELF 段] [guard] [heap ─brk→] ... [←mmap─] [guard] [stack 8MB预留]
//   ↑                ↑                ↑                  ↑
// p_vaddr       heap_bottom      MMAP_BASE        USER_STACK_TOP
//
// - heap:  紧贴 ELF 段后，brk(2) 向高地址扩展（from_elf 创建空占位）
// - stack: 固定在 USER_STACK_TOP，sp 向低地址增长
// - mmap:  从 MMAP_BASE 向低地址分配，与 brk 背向而行永不冲突
// - kernel space top: 内核地址空间顶部预留给中断栈/内核栈布局
//
// 多线程栈排列：tid_N 的栈向低地址排列 (tid_0 最靠近 USER_STACK_TOP)
// tid 分配见 ustack_bottom_from_tid() in task/id.rs
// ============================================================

#[allow(unused)]

pub const USER_STACK_SIZE: usize = 4096 * 32;       // 128 KB 初始 MapArea
pub const USER_STACK_GUARD: usize = 4096 * 4;       // 16 KB 栈下方 guard gap
pub const USER_STACK_MAX: usize = 8 * 1024 * 1024;  // 8 MB 栈自动增长上限（待实现）
pub const KERNEL_STACK_SIZE: usize = 4096 * 16;     // 64 KB（main: exec wrapper 栈溢出修复）
pub const KERNEL_STACK_GUARD_SIZE: usize = 4096;
pub const KERNEL_HEAP_SIZE: usize = 0x800_0000; // 128 MB
pub const PAGE_SIZE: usize = 0x1000;
pub const PAGE_SIZE_BITS: usize = 0xc;
pub use polyhal::kernel_layout::{
    KERNEL_INTR_STACK_BOTTOM, KERNEL_INTR_STACK_SIZE, KERNEL_INTR_STACK_TOP, KERNEL_SPACE_TOP,
};

/// 用户栈顶：Sv39 用户空间顶部 (~256 GB) 向下增长。
/// 调用者应 `let ustack_base = USER_STACK_TOP - USER_STACK_SIZE;`
pub const USER_STACK_TOP: usize = 0x3F_FFFF_F000;
/// mmap 分配基址，sys_mmap(addr=0) 从此处向低地址分配。
pub const MMAP_BASE: usize = USER_STACK_TOP - USER_STACK_MAX - USER_STACK_GUARD;

/// 动态链接器（ld.so）加载时的虚拟地址偏移量。
///
/// 主程序占据低地址区域（p_vaddr 原值），ld.so 及未来共享库统一
/// 加载到高地址区域（p_vaddr + DL_INTERP_OFFSET），避免两个独立编译
/// 的 ELF 在同一页表中发生 VA 冲突。
///
/// 必须 < 0x40_0000_0000（Sv39 用户空间上界 256GB），否则 ld.so
/// 映射到内核地址区 → 用户态取指立即 InstructionPageFault 死循环。
pub const DL_INTERP_OFFSET: usize = 0x20_0000_0000;

pub use crate::arch::board::{CLOCK_FREQ, MEMORY_END, MMIO};

