mod virtio_blk;

pub use virtio_blk::VirtIOBlock;

use alloc::sync::Arc;
use alloc::format;
use lazy_static::*;

// 注意：这里保留具体类型 Arc<VirtIOBlock>。
// handle_irq 不再属于 BlockDevice trait，而是 VirtIOBlock 的固有方法，由 qemu.rs 的 IRQ handler 直接调用。
// filesystem crate 通过 Arc::clone 获取 Arc<dyn filesystem::device::BlockDevice>。
lazy_static! {
    pub static ref BLOCK_DEVICE: Arc<VirtIOBlock> = Arc::new(VirtIOBlock::new());
}

/// 第二 block 设备（x1/disk.img），用于 libgcc_s.so.1 等辅助文件。
/// 仅在 RISC-V 上由 fs::init() 设置，LoongArch 暂不支持。
pub static VDB_DEVICE: spin::Once<Arc<VirtIOBlock>> = spin::Once::new();

/// 在文件系统注册块设备之前，显式完成 virtio-blk 驱动实例化。
///
/// 当前 `BLOCK_DEVICE` 仍使用 `lazy_static!` 持有，但初始化时机不应由
/// `fs::init()` 里的第一次 `clone()` / `debug_irq_state()` 被动触发。
pub fn init() {
    lazy_static::initialize(&BLOCK_DEVICE);
}

pub fn register_block_device(dev_name: &str, device: Arc<VirtIOBlock>) {
    polyhal::println!("[block] register_block_device start: {}", dev_name);
    // 文件系统通过 device::register_block_device 注册设备并获取全局唯一 dev_id。
    filesystem::device::register_block_device(dev_name, device.clone());
    polyhal::println!("[block] device registered, about to scan MBR");
    if let Some(partitions) = filesystem::device::scan_mbr_partitions(device.clone()) {
        polyhal::println!("[block] MBR scan found {} partitions", partitions.len());
        for partition in partitions {
            let part_name = format!("{}{}", dev_name, partition.index);
            let part_dev = filesystem::device::make_partition_block_device(
                device.clone(),
                partition.start_lba,
                partition.sector_count,
            );
            filesystem::device::register_block_device(part_name.as_str(), part_dev.clone());
            polyhal::println!(
                "[block] registered partition {} type=0x{:02x} start_lba={} sectors={}",
                part_name,
                partition.partition_type,
                partition.start_lba,
                partition.sector_count
            );
            if let Some(info) = filesystem::fat::probe_fat_volume(part_dev.clone()) {
                polyhal::println!(
                    "[block] {} looks like {:?} bps={} spc={} total_sectors={}",
                    part_name,
                    info.fat_type,
                    info.bytes_per_sector,
                    info.sectors_per_cluster,
                    info.total_sectors
                );
            }
        }
    } else {
        polyhal::println!("[block] no MBR partitions found");
    }
    polyhal::println!("[block] register_block_device done: {}", dev_name);
}

#[allow(unused)]
pub fn block_device_test() {
    use filesystem::device::BlockDevice;
    let block_device = BLOCK_DEVICE.clone();
    let mut write_buffer = [0u8; 512];
    let mut read_buffer = [0u8; 512];
    for i in 0..512 {
        for byte in write_buffer.iter_mut() {
            *byte = i as u8;
        }
        block_device.write_block(i as usize, &mut write_buffer);
        block_device.read_block(i as usize, &mut read_buffer);
        assert_eq!(write_buffer, read_buffer);
    }
    println!("block device test passed!");
}

