use core::any::Any;
use core::ptr::NonNull;

use crate::drivers::bus::virtio::VirtioHal;
use crate::sync::UPIntrFreeCell;
use alloc::{sync::Arc, vec::Vec};
use embedded_graphics::pixelcolor::Rgb888;
use tinybmp::Bmp;
use virtio_drivers::device::gpu::VirtIOGpu;
use virtio_drivers::transport::mmio::{MmioTransport, VirtIOHeader};

const VIRTIO7: usize = 0x10007000;

pub trait GpuDevice: Send + Sync + Any {
    fn get_framebuffer(&self) -> &mut [u8];
    fn flush(&self);
}

lazy_static::lazy_static!(
    pub static ref GPU_DEVICE: Arc<dyn GpuDevice> = Arc::new(VirtIOGpuWrapper::new());
);

pub struct VirtIOGpuWrapper {
    gpu: UPIntrFreeCell<VirtIOGpu<VirtioHal, MmioTransport>>,
    fb: &'static [u8],
}

// SAFETY: UP 单核环境，关中断互斥访问，实际 Send + Sync。
unsafe impl Send for VirtIOGpuWrapper {}
unsafe impl Sync for VirtIOGpuWrapper {}

static BMP_DATA: &[u8] = include_bytes!("../../assert/mouse.bmp");

impl VirtIOGpuWrapper {
    pub fn new() -> Self {
        let header = NonNull::new((VIRTIO7 | polyhal::consts::VIRT_ADDR_START) as *mut VirtIOHeader)
            .expect("VIRTIO7 VA is null");
        let transport = unsafe {
            MmioTransport::new(header)
        }.expect("failed to create MmioTransport for virtio-gpu");

        let mut virtio =
            VirtIOGpu::<VirtioHal, MmioTransport>::new(transport)
                .expect("failed to create VirtIOGpu");

        let fbuffer = virtio.setup_framebuffer().expect("failed to setup framebuffer");
        let len = fbuffer.len();
        let ptr = fbuffer.as_mut_ptr();
        // SAFETY: fbuffer 的生命周期由 VirtIOGpu 内部的 Dma 持有，
        // 且 VirtIOGpu 被移入 UPIntrFreeCell，地址在 Drop 前不变。
        // 存储为共享引用以通过 Send/Sync 检查，访问时再转 *mut。
        let fb: &'static [u8] = unsafe { core::slice::from_raw_parts(ptr, len) };

        let bmp = Bmp::<Rgb888>::from_slice(BMP_DATA).unwrap();
        let raw = bmp.as_raw();
        let mut b = Vec::new();
        for i in raw.image_data().chunks(3) {
            let mut v = i.to_vec();
            b.append(&mut v);
            if i == [255, 255, 255] {
                b.push(0x0)
            } else {
                b.push(0xff)
            }
        }
        virtio.setup_cursor(b.as_slice(), 50, 50, 50, 50).unwrap();

        Self {
            gpu: unsafe { UPIntrFreeCell::new(virtio) },
            fb,
        }
    }
}

impl GpuDevice for VirtIOGpuWrapper {
    fn flush(&self) {
        self.gpu.exclusive_access().flush().unwrap();
    }
    fn get_framebuffer(&self) -> &mut [u8] {
        unsafe {
            let ptr = self.fb.as_ptr() as *const _ as *mut u8;
            core::slice::from_raw_parts_mut(ptr, self.fb.len())
        }
    }
}

