use crate::task::{
    KContext, TaskControlBlock, block_current_and_run_next, block_current_task,
    clear_current_block_reason, current_task, schedule, set_current_block_reason,
    suspend_current_and_run_next, wakeup_task,
};
use alloc::sync::Arc;
use polyhal::irq::IRQ;

pub use ksync::{
    Condvar, Mutex, MutexBlocking, MutexSpin, Semaphore, UPIntrFreeCell, UPIntrRefMut,
    UPSafeCellRaw,
};

fn current_task_raw() -> usize {
    Arc::into_raw(current_task().expect("current_task not available")) as usize
}

fn clone_task_raw(raw: usize) -> usize {
    let task = unsafe { Arc::from_raw(raw as *const TaskControlBlock) };
    let cloned = Arc::clone(&task);
    let _ = Arc::into_raw(task);
    Arc::into_raw(cloned) as usize
}

fn drop_task_raw(raw: usize) {
    unsafe {
        drop(Arc::from_raw(raw as *const TaskControlBlock));
    }
}

fn wakeup_task_raw(raw: usize) {
    let task = unsafe { Arc::from_raw(raw as *const TaskControlBlock) };
    wakeup_task(task);
}

fn block_current_task_raw() -> *mut () {
    block_current_task() as *mut ()
}

fn schedule_raw(task_cx_ptr: *mut ()) {
    schedule(task_cx_ptr.cast::<KContext>());
}

pub fn init() {
    ksync::init_irq_ops(ksync::IrqOps {
        int_enabled: IRQ::int_enabled,
        int_enable: IRQ::int_enable,
        int_disable: IRQ::int_disable,
    });
    ksync::init_task_ops(ksync::TaskRuntimeOps {
        current_task: current_task_raw,
        clone_task: clone_task_raw,
        drop_task: drop_task_raw,
        wakeup_task: wakeup_task_raw,
        set_current_block_reason,
        clear_current_block_reason,
        block_current_and_run_next,
        suspend_current_and_run_next,
        block_current_task: block_current_task_raw,
        schedule: schedule_raw,
    });
}

